wp:postmeta.wp:meta_value:
a:7:{s:8:"metadata";a:5:{s:4:"type";s:8:"template";s:9:"shortcode";s:38:"s-98491cbc-8274-4a0a-a50c-548f24fb611d";s:9:"isPrimary";s:0:"";s:5:"title";s:3:"FAQ";s:23:"reviewLocationShortcode";s:24:"[rank_math_rich_snippet]";}s:5:"@type";s:7:"FAQPage";s:4:"name";s:60:"سوالات متداول درباره چگالی استیل";s:3:"url";s:5:"%url%";s:13:"datePublished";s:20:"%date(Y-m-dTH:i:sP)%";s:12:"dateModified";s:24:"%modified(Y-m-dTH:i:sP)%";s:10:"mainEntity";a:5:{i:0;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:32:"چگالی استیل چیست؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:338:"چگالی مقدار جرم در واحد حجم است و برای استنلس استیل معمولاً در بازه 7.7 تا 8.0 g/cm³ قرار می‌گیرد. چگالی مستقیماً به ترکیب شیمیایی آلیاژ وابسته است و با تغییر ضخامت یا شکل محصول تغییر نمی‌کند.";}}i:1;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:43:"چگالی استیل 304 چقدر است؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:218:"چگالی اسمی استیل 304 برابر 7.9 g/cm³ یا 7900 kg/m³ است. این مقدار برای محاسبه وزن ورق، لوله، پروفیل و سایر مقاطع 304 استفاده می‌شود.";}}i:2;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:43:"چگالی استیل 316 چقدر است؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:173:"چگالی 316 حدود 8.0 g/cm³ است. وجود مولیبدن در ترکیب این گرید موجب افزایش جزئی چگالی نسبت به 304 می‌شود.";}}i:3;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:68:"چگالی ورق استیل چگونه محاسبه می‌شود؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:239:"چگالی مقدار ثابتی است. وزن ورق از فرمول زیر به دست می‌آید:
وزن = طول × عرض × ضخامت × چگالی
برای 304 عدد 7.9 و برای 316 عدد 8.0 استفاده می‌شود.";}}i:4;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:59:"چرا چگالی استیل 201 کمتر از 304 است؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:232:"استیل 201 نیکل کمتری دارد و جایگزینی بخشی از نیکل با منگنز باعث کاهش چگالی می‌شود. به همین دلیل وزن محصولات 201 همیشه کمتر از 304 است.";}}}}

a:7:{s:8:"metadata";a:5:{s:4:"type";s:8:"template";s:9:"shortcode";s:38:"s-af785b87-bc36-42b4-b10f-9cffa881b0b2";s:9:"isPrimary";s:0:"";s:5:"title";s:3:"FAQ";s:23:"reviewLocationShortcode";s:24:"[rank_math_rich_snippet]";}s:5:"@type";s:7:"FAQPage";s:4:"name";s:58:"سوالات متداول لوله استیل (304 و 316)";s:3:"url";s:5:"%url%";s:13:"datePublished";s:20:"%date(Y-m-dTH:i:sP)%";s:12:"dateModified";s:24:"%modified(Y-m-dTH:i:sP)%";s:10:"mainEntity";a:5:{i:0;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:70:"لوله استیل 304 بهتر است یا لوله استیل 316؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:297:"اگر محیط خورنده، اسیدی، کلر بالا یا نزدیک دریا دارید، 316 انتخاب مطمئن‌تری است. اگر کاربرد عمومی و صنعتی معمولی دارید، 304 کاملاً مناسب است و قیمت پایین‌تری نیز دارد.";}}i:1;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:67:"ضخامت رده 40 برای لوله استیل چقدر است؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:164:"ضخامت بسته به سایز متفاوت است. در سایز 2 اینچ، لوله استیل رده 40 حدود 3.91 میلی‌متر ضخامت دارد.";}}i:2;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:31:"تفاوت NPS و OD چیست؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:196:"NPS یک سایز نامی است و قطر واقعی لوله محسوب نمی‌شود. OD همان قطر خارجی واقعی است که در جداول استاندارد مشخص است.";}}i:3;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:66:"وزن لوله استیل چگونه محاسبه می‌شود؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:178:"وزن بر اساس فرمول
ρ × 3.14 × (OD − THK) × THK
محاسبه می‌شود. همچنین جدول وزن آماده در بخش قبل ارائه شده است.";}}i:4;a:3:{s:5:"@type";s:8:"Question";s:4:"name";s:60:"استاندارد لوله استیل 304 و 316 چیست؟";s:14:"acceptedAnswer";a:2:{s:5:"@type";s:6:"Answer";s:4:"text";s:124:"استانداردهای اصلی شامل ASTM A312، A213، A269، A270 و برای لوله دکوراتیو A554 است.";}}}}
